css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #1a120b; color: #f5ebe0; overflow-x: hidden; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 22px 60px; }
.brand { font-size: 20px; font-weight: 800; }
.nav-links { display: flex; gap: 32px; }
.nav-links a { color: rgba(245,235,224,0.65); text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-btn { background: linear-gradient(135deg, #c08552, #8b5a2b); border: none; color: white; padding: 11px 26px; border-radius: 999px; font-size: 13.5px; font-weight: 700; cursor: pointer; }
.hero { display: flex; align-items: center; justify-content: space-between; padding: 60px 60px 100px; gap: 60px; flex-wrap: wrap; }
.hero-text { max-width: 520px; }
.badge { display: inline-block; background: rgba(192,133,82,0.18); color: #d9a774; font-size: 12.5px; font-weight: 700; padding: 6px 16px; border-radius: 999px; margin-bottom: 20px; }
.hero-text h1 { font-size: 54px; font-weight: 800; line-height: 1.15; margin-bottom: 18px; }
.hero-text h1 span { color: #d9a774; }
.hero-text p { color: rgba(245,235,224,0.6); font-size: 16px; line-height: 1.7; margin-bottom: 28px; }
.hero-actions { display: flex; gap: 14px; }
.btn-primary { background: linear-gradient(135deg, #c08552, #8b5a2b); border: none; color: white; padding: 15px 30px; border-radius: 12px; font-size: 14px; font-weight: 700; cursor: pointer; box-shadow: 0 12px 30px rgba(192,133,82,0.3); }
.btn-secondary { background: rgba(245,235,224,0.06); border: 1px solid rgba(245,235,224,0.18); color: #f5ebe0; padding: 15px 30px; border-radius: 12px; font-size: 14px; font-weight: 700; cursor: pointer; }
.hero-visual { position: relative; width: 280px; height: 280px; display: flex; align-items: center; justify-content: center; }
.cup { font-size: 140px; }
.bean { position: absolute; font-size: 36px; animation: float 4s ease-in-out infinite; }
.bean-1 { top: 10px; right: 20px; animation-delay: 0s; }
.bean-2 { bottom: 30px; left: 10px; animation-delay: 1s; }
.bean-3 { top: 60px; left: -20px; animation-delay: 2s; }
@keyframes float { 0%, 100% { transform: translateY(0) rotate(0deg); } 50% { transform: translateY(-14px) rotate(15deg); } }
.menu { padding: 60px; text-align: center; }
.menu h2 { font-size: 36px; font-weight: 800; margin-bottom: 48px; }
.menu-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 24px; max-width: 1100px; margin: 0 auto; }
.menu-card { background: rgba(245,235,224,0.04); border: 1px solid rgba(245,235,224,0.08); border-radius: 18px; padding: 28px; text-align: left; }
.menu-icon { font-size: 36px; margin-bottom: 14px; }
.menu-card h3 { font-size: 18px; font-weight: 700; margin-bottom: 8px; }
.menu-card p { color: rgba(245,235,224,0.5); font-size: 13.5px; line-height: 1.6; margin-bottom: 14px; }
.price { color: #d9a774; font-weight: 800; font-size: 16px; }
.story { display: flex; align-items: center; gap: 60px; padding: 60px; flex-wrap: wrap; }
.story-img { flex: 1; min-width: 240px; height: 320px; background: rgba(245,235,224,0.04); border-radius: 24px; display: flex; align-items: center; justify-content: center; font-size: 60px; }
.story-text { flex: 1; min-width: 280px; }
.story-text h2 { font-size: 32px; font-weight: 800; margin-bottom: 18px; }
.story-text p { color: rgba(245,235,224,0.55); font-size: 15px; line-height: 1.8; margin-bottom: 28px; }
.story-stats { display: flex; gap: 36px; }
.story-stats div { display: flex; flex-direction: column; }
.story-stats strong { font-size: 24px; font-weight: 800; color: #d9a774; }
.story-stats span { font-size: 12.5px; color: rgba(245,235,224,0.45); }
.cta { text-align: center; padding: 80px 60px; background: linear-gradient(135deg, rgba(192,133,82,0.12), rgba(139,90,43,0.12)); }
.cta h2 { font-size: 30px; font-weight: 800; margin-bottom: 28px; }
@media (max-width: 900px) { .hero, .story { padding: 40px 24px; flex-direction: column; } .hero-text h1 { font-size: 38px; } .menu { padding: 50px 24px; } }

